func (h *rsaPrivateKey) Set(name string, value any) error {
	h.mu.Lock()
	defer h.mu.Unlock()
	return h.setNoLock(name, value)
}

func (h *rsaPrivateKey) setNoLock(name string, value any) error {
	switch name {
	case "kty":
		return nil
	case AlgorithmKey:
		switch v := value.(type) {
		case string, jwa.SignatureAlgorithm, jwa.KeyEncryptionAlgorithm, jwa.ContentEncryptionAlgorithm:
			tmp, err := jwa.KeyAlgorithmFrom(v)
			if err != nil {
				return fmt.Errorf(`invalid algorithm for %q key: %w`, AlgorithmKey, err)
			}
			h.algorithm = &tmp
		default:
			return fmt.Errorf(`invalid type for %q key: %T`, AlgorithmKey, value)
		}
		return nil
	case RSADKey:
		if v, ok := value.([]byte); ok {
			if v == nil {
				h.d = nil
			} else {
				h.d = make([]byte, len(v))
				copy(h.d, v)
			}
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, RSADKey, value)
	case RSADPKey:
		if v, ok := value.([]byte); ok {
			if v == nil {
				h.dp = nil
			} else {
				h.dp = make([]byte, len(v))
				copy(h.dp, v)
			}
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, RSADPKey, value)
	case RSADQKey:
		if v, ok := value.([]byte); ok {
			if v == nil {
				h.dq = nil
			} else {
				h.dq = make([]byte, len(v))
				copy(h.dq, v)
			}
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, RSADQKey, value)
	case RSAEKey:
		if v, ok := value.([]byte); ok {
			if v == nil {
				h.e = nil
			} else {
				h.e = make([]byte, len(v))
				copy(h.e, v)
			}
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, RSAEKey, value)
	case KeyIDKey:
		if v, ok := value.(string); ok {
			h.keyID = &v
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, KeyIDKey, value)
	case KeyOpsKey:
		var acceptor KeyOperationList
		if err := acceptor.Accept(value); err != nil {
			return fmt.Errorf(`invalid value for %s key: %w`, KeyOpsKey, err)
		}
		h.keyOps = &acceptor
		return nil
	case KeyUsageKey:
		switch v := value.(type) {
		case KeyUsageType:
			switch v {
			case ForSignature, ForEncryption:
				tmp := v.String()
				h.keyUsage = &tmp
			default:
				return fmt.Errorf(`invalid key usage type %s`, v)
			}
		case string:
			h.keyUsage = &v
		default:
			return fmt.Errorf(`invalid key usage type %s`, v)
		}
	case RSANKey:
		if v, ok := value.([]byte); ok {
			if v == nil {
				h.n = nil
			} else {
				h.n = make([]byte, len(v))
				copy(h.n, v)
			}
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, RSANKey, value)
	case RSAPKey:
		if v, ok := value.([]byte); ok {
			if v == nil {
				h.p = nil
			} else {
				h.p = make([]byte, len(v))
				copy(h.p, v)
			}
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, RSAPKey, value)
	case RSAQKey:
		if v, ok := value.([]byte); ok {
			if v == nil {
				h.q = nil
			} else {
				h.q = make([]byte, len(v))
				copy(h.q, v)
			}
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, RSAQKey, value)
	case RSAQIKey:
		if v, ok := value.([]byte); ok {
			if v == nil {
				h.qi = nil
			} else {
				h.qi = make([]byte, len(v))
				copy(h.qi, v)
			}
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, RSAQIKey, value)
	case X509CertChainKey:
		if v, ok := value.(*cert.Chain); ok {
			h.x509CertChain = v
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, X509CertChainKey, value)
	case X509CertThumbprintKey:
		if v, ok := value.(string); ok {
			h.x509CertThumbprint = &v
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, X509CertThumbprintKey, value)
	case X509CertThumbprintS256Key:
		if v, ok := value.(string); ok {
			h.x509CertThumbprintS256 = &v
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, X509CertThumbprintS256Key, value)
	case X509URLKey:
		if v, ok := value.(string); ok {
			h.x509URL = &v
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, X509URLKey, value)
	default:
		if h.privateParams == nil {
			h.privateParams = map[string]any{}
		}
		h.privateParams[name] = value
	}
	return nil
}

func (k *rsaPrivateKey) Remove(key string) error {
	k.mu.Lock()
	defer k.mu.Unlock()
	switch key {
	case AlgorithmKey:
		k.algorithm = nil
	case RSADKey:
		k.d = nil
	case RSADPKey:
		k.dp = nil
	case RSADQKey:
		k.dq = nil
	case RSAEKey:
		k.e = nil
	case KeyIDKey:
		k.keyID = nil
	case KeyOpsKey:
		k.keyOps = nil
	case KeyUsageKey:
		k.keyUsage = nil
	case RSANKey:
		k.n = nil
	case RSAPKey:
		k.p = nil
	case RSAQKey:
		k.q = nil
	case RSAQIKey:
		k.qi = nil
	case X509CertChainKey:
		k.x509CertChain = nil
	case X509CertThumbprintKey:
		k.x509CertThumbprint = nil
	case X509CertThumbprintS256Key:
		k.x509CertThumbprintS256 = nil
	case X509URLKey:
		k.x509URL = nil
	default:
		delete(k.privateParams, key)
	}
	return nil
}

func (dst *rsaPrivateKey) cloneFrom(src *rsaPrivateKey) {
	src.mu.RLock()
	defer src.mu.RUnlock()
	dst.mu.Lock()
	defer dst.mu.Unlock()
	if src.algorithm != nil {
		tmp := *(src.algorithm)
		dst.algorithm = &tmp
	} else {
		dst.algorithm = nil
	}
	if src.d != nil {
		dst.d = slices.Clone(src.d)
	} else {
		dst.d = nil
	}
	if src.dp != nil {
		dst.dp = slices.Clone(src.dp)
	} else {
		dst.dp = nil
	}
	if src.dq != nil {
		dst.dq = slices.Clone(src.dq)
	} else {
		dst.dq = nil
	}
	if src.e != nil {
		dst.e = slices.Clone(src.e)
	} else {
		dst.e = nil
	}
	if src.keyID != nil {
		tmp := *(src.keyID)
		dst.keyID = &tmp
	} else {
		dst.keyID = nil
	}
	if src.keyOps != nil {
		tmp := slices.Clone(*src.keyOps)
		dst.keyOps = &tmp
	} else {
		dst.keyOps = nil
	}
	if src.keyUsage != nil {
		tmp := *(src.keyUsage)
		dst.keyUsage = &tmp
	} else {
		dst.keyUsage = nil
	}
	if src.n != nil {
		dst.n = slices.Clone(src.n)
	} else {
		dst.n = nil
	}
	if src.p != nil {
		dst.p = slices.Clone(src.p)
	} else {
		dst.p = nil
	}
	if src.q != nil {
		dst.q = slices.Clone(src.q)
	} else {
		dst.q = nil
	}
	if src.qi != nil {
		dst.qi = slices.Clone(src.qi)
	} else {
		dst.qi = nil
	}
	if src.x509CertChain != nil {
		dst.x509CertChain = src.x509CertChain
	} else {
		dst.x509CertChain = nil
	}
	if src.x509CertThumbprint != nil {
		tmp := *(src.x509CertThumbprint)
		dst.x509CertThumbprint = &tmp
	} else {
		dst.x509CertThumbprint = nil
	}
	if src.x509CertThumbprintS256 != nil {
		tmp := *(src.x509CertThumbprintS256)
		dst.x509CertThumbprintS256 = &tmp
	} else {
		dst.x509CertThumbprintS256 = nil
	}
	if src.x509URL != nil {
		tmp := *(src.x509URL)
		dst.x509URL = &tmp
	} else {
		dst.x509URL = nil
	}
	if len(src.privateParams) > 0 {
		dst.privateParams = make(map[string]any, len(src.privateParams))
		for k, v := range src.privateParams {
			dst.privateParams[k] = v
		}
	} else {
		dst.privateParams = nil
	}
}

func (k *rsaPrivateKey) Clone() (Key, error) {
	dst := newRSAPrivateKey()
	dst.cloneFrom(k)
	return dst, nil
}

func (k *rsaPrivateKey) DecodeCtx() json.DecodeCtx {
	k.mu.RLock()
	defer k.mu.RUnlock()
	return k.dc
}

func (k *rsaPrivateKey) SetDecodeCtx(dc json.DecodeCtx) {
	k.mu.Lock()
	defer k.mu.Unlock()
	k.dc = dc
}

func (h *rsaPrivateKey) UnmarshalJSON(buf []byte) (retErr error) {
	h.mu.Lock()
	defer h.mu.Unlock()
	h.algorithm = nil
	h.d = nil
	h.dp = nil
	h.dq = nil
	h.e = nil
	h.keyID = nil
	h.keyOps = nil
	h.keyUsage = nil
	h.n = nil
	h.p = nil
	h.q = nil
	h.qi = nil
	h.x509CertChain = nil
	h.x509CertThumbprint = nil
	h.x509CertThumbprintS256 = nil
	h.x509URL = nil
	defer func() {
		if retErr != nil {
			clear(h.d)
			h.d = nil
			clear(h.dp)
			h.dp = nil
			clear(h.dq)
			h.dq = nil
			clear(h.e)
			h.e = nil
			clear(h.n)
			h.n = nil
			clear(h.p)
			h.p = nil
			clear(h.q)
			h.q = nil
			clear(h.qi)
			h.qi = nil
		}
	}()
	dec := json.NewDecoder(bytes.NewReader(buf))
	tok, err := dec.ReadToken()
	if err != nil {
		return fmt.Errorf(`error reading token: %w`, err)
	}
	if tok.Kind() != '{' {
		return fmt.Errorf(`expected '{' but got '%c'`, tok.Kind())
	}
	for dec.PeekKind() != '}' {
		tok, err := dec.ReadToken()
		if err != nil {
			return fmt.Errorf(`error reading token: %w`, err)
		}
		switch tok.String() {
		case KeyTypeKey:
			val, err := json.ReadNextStringToken(dec, h.dc)
			if err != nil {
				return fmt.Errorf(`error reading token: %w`, err)
			}
			if val != jwa.RSA().String() {
				return fmt.Errorf(`invalid kty value for RSAPublicKey (%s)`, val)
			}
		case AlgorithmKey:
			// "alg" is an informational hint stored as-is, not validated against the key type here; see [ParseKey] for rationale.
			var s string
			if err := json.UnmarshalDecode(dec, &s); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, AlgorithmKey, err)
			}
			alg, err := jwa.KeyAlgorithmFrom(s)
			if err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, AlgorithmKey, err)
			}
			h.algorithm = &alg
		case RSADKey:
			if err := json.AssignNextBytesToken(&h.d, dec); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, RSADKey, err)
			}
		case RSADPKey:
			if err := json.AssignNextBytesToken(&h.dp, dec); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, RSADPKey, err)
			}
		case RSADQKey:
			if err := json.AssignNextBytesToken(&h.dq, dec); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, RSADQKey, err)
			}
		case RSAEKey:
			if err := json.AssignNextBytesToken(&h.e, dec); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, RSAEKey, err)
			}
		case KeyIDKey:
			if err := json.AssignNextStringToken(&h.keyID, dec, h.dc); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, KeyIDKey, err)
			}
		case KeyOpsKey:
			var decoded KeyOperationList
			if err := json.UnmarshalDecode(dec, &decoded); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, KeyOpsKey, err)
			}
			h.keyOps = &decoded
		case KeyUsageKey:
			val, err := json.ReadNextStringToken(dec, h.dc)
			if err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, KeyUsageKey, err)
			}
			var acceptor KeyUsageType
			if err := acceptor.Accept(val); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, KeyUsageKey, err)
			}
			tmp := acceptor.String()
			h.keyUsage = &tmp
		case RSANKey:
			if err := json.AssignNextBytesToken(&h.n, dec); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, RSANKey, err)
			}
		case RSAPKey:
			if err := json.AssignNextBytesToken(&h.p, dec); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, RSAPKey, err)
			}
		case RSAQKey:
			if err := json.AssignNextBytesToken(&h.q, dec); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, RSAQKey, err)
			}
		case RSAQIKey:
			if err := json.AssignNextBytesToken(&h.qi, dec); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, RSAQIKey, err)
			}
		case X509CertChainKey:
			var decoded cert.Chain
			if err := json.UnmarshalDecode(dec, &decoded); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, X509CertChainKey, err)
			}
			h.x509CertChain = &decoded
		case X509CertThumbprintKey:
			if err := json.AssignNextStringToken(&h.x509CertThumbprint, dec, h.dc); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, X509CertThumbprintKey, err)
			}
		case X509CertThumbprintS256Key:
			if err := json.AssignNextStringToken(&h.x509CertThumbprintS256, dec, h.dc); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, X509CertThumbprintS256Key, err)
			}
		case X509URLKey:
			if err := json.AssignNextStringToken(&h.x509URL, dec, h.dc); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, X509URLKey, err)
			}
		default:
			fieldName := tok.String()
			raw, err := dec.ReadValue()
			if err != nil {
				return fmt.Errorf(`could not read value for field %s: %w`, fieldName, err)
			}
			if dc := h.dc; dc != nil {
				if localReg := dc.Registry(); localReg != nil {
					decoded, err := localReg.Decode(fieldName, raw)
					if err == nil {
						h.setNoLock(fieldName, decoded)
						continue
					}
				}
			}
			decoded, err := fieldRegistry.Decode(fieldName, raw)
			if err == nil {
				h.setNoLock(fieldName, decoded)
				continue
			}
			return fmt.Errorf(`could not decode field %s: %w`, fieldName, err)
		}
	}
	// consume closing '}'
	if _, err := dec.ReadToken(); err != nil {
		return fmt.Errorf(`error reading closing token: %w`, err)
	}
	if h.d == nil {
		return fmt.Errorf(`required field d is missing`)
	}
	if h.e == nil {
		return fmt.Errorf(`required field e is missing`)
	}
	if h.n == nil {
		return fmt.Errorf(`required field n is missing`)
	}
	return nil
}

